if (blockNumber % getEpochSize() == 0) {
  if (lastEpochBlock < historyFirst) {
    delete history[lastEpochBlock];
  }
  lastEpochBlock = blockNumber;
} else {
  if (historySize == 0) {
    historyFirst = blockNumber;
    historySize = 1;
  } else if (historySize > deprecated_randomnessBlockRetentionWindow) {
    deleteHistoryIfNotLastEpochBlock(historyFirst);
    deleteHistoryIfNotLastEpochBlock(historyFirst.add(1));
    historyFirst = historyFirst.add(2);
    historySize = historySize.sub(1);
  } else if (historySize == deprecated_randomnessBlockRetentionWindow) {
    deleteHistoryIfNotLastEpochBlock(historyFirst);
    historyFirst = historyFirst.add(1);
  } else {
    // historySize < deprecated_randomnessBlockRetentionWindow
    historySize = historySize.add(1);
  }
}

if (neededAmount > 0) {
    // Make sure the payer is transferring the right amount to this contract
    if (
        _signatureTransferData.transferDetails.to != address(this) ||
        _signatureTransferData.transferDetails.requestedAmount != neededAmount
    ) {
        revert InvalidTransferDetails();
    }

    // Record our balance before (most likely zero) to detect fee-on-transfer tokens
    uint256 balanceBefore = erc20.balanceOf(address(this));

    // Transfer the payment token to this contract
    permit2.permitTransferFrom(
        _signatureTransferData.permit,
        _signatureTransferData.transferDetails,
        _msgSender(),
        _signatureTransferData.signature
    );

    // Make sure this is not a fee-on-transfer token
    revertIfInexactTransfer(neededAmount, balanceBefore, erc20, address(this));

    // Complete the payment
    transferFundsToDestinations(_intent);
}

if (rebateRate > 0) {
    // If the rebate rate is not zero, maker pays no fees.
    result.makerFee = 0;

    // RebateRate will never exceed REBATE_RATE_BASE, so rebateFee will never exceed the fees paid by the taker.
    result.makerRebate = result.quoteTokenFilledAmount.mul(takerFeeRate).mul(rebateRate).div(
        FEE_RATE_BASE.mul(DISCOUNT_RATE_BASE).mul(REBATE_RATE_BASE)
    );
} else {
    uint256 makerRawFeeRate = getAsMakerFeeRateFromOrderData(makerOrderParam.data);
    result.makerRebate = 0;

    // maker fee will be reduced, but still >= 0
    uint256 makerFeeRate = getFinalFeeRate(
        makerOrderParam.trader,
        makerRawFeeRate,
        isParticipantRelayer
    );

    result.makerFee = result.quoteTokenFilledAmount.mul(makerFeeRate).div(
        FEE_RATE_BASE.mul(DISCOUNT_RATE_BASE)
    );
}

for (
    RRUtils.RRIterator memory iter = rrset.rrs();
    !iter.done();
    iter.next()
) {
    // We only support class IN (Internet)
    if (iter.class != DNSCLASS_IN) {
        revert InvalidClass(iter.class);
    }

    if (name.length == 0) {
        name = iter.name();
    } else {
        // Name must be the same on all RRs. We do things this way to avoid copying the name
        // repeatedly.
        if (
            name.length != iter.data.nameLength(iter.offset) ||
            !name.equals(0, iter.data, iter.offset, name.length)
        ) {
            revert InvalidRRSet();
        }
    }

    // o  The RRSIG RR's Type Covered field MUST equal the RRset's type.
    if (iter.dnstype != typecovered) {
        revert SignatureTypeMismatch(iter.dnstype, typecovered);
    }
}

for (uint256 i = 0; i < signers.length; ++i) {
    bytes memory signer = signers[i];
    require(isSigner(account, signer), ERC7579MultisigNonexistentSigner(signer));

    uint64 weight = weights[i];
    require(weight > 0, ERC7579MultisigInvalidWeight(signer, weight));

    unchecked {
        uint64 oldExtraWeight = _extraWeights[account][signer];
        uint64 newExtraWeight = weight - 1;

        if (oldExtraWeight != newExtraWeight) {
            // Overflow impossible: weight values are bounded by uint64 and economic constraints
            extraWeightRemoved += oldExtraWeight;
            extraWeightAdded += _extraWeights[account][signer] = newExtraWeight;
            emit ERC7579MultisigWeightChanged(account, signer, weight);
        }
    }
}

if (batchSize > 0) {
    if (address(this).code.length > 0) {
        revert ERC721ForbiddenBatchMint();
    }
    if (to == address(0)) {
        revert ERC721InvalidReceiver(address(0));
    }

    uint256 maxBatchSize = _maxBatchSize();
    if (batchSize > maxBatchSize) {
        revert ERC721ExceededMaxBatchMint(batchSize, maxBatchSize);
    }

    // push an ownership checkpoint & emit event
    uint96 last = next + batchSize - 1;
    $._sequentialOwnership.push(last, uint160(to));

    // The invariant required by this function is preserved because the new sequentialOwnership checkpoint
    // is attributing ownership of `batchSize` new tokens to account `to`.
    _increaseBalance(to, batchSize);

    emit ConsecutiveTransfer(next, last, address(0), to);
}

if (isTargetClosed(target)) {
    return (false, 0);
} else if (caller == address(this)) {
    // Caller is AccessManager, this means the call was sent through {execute} and it already checked
    // permissions. We verify that the call "identifier", which is set during {execute}, is correct.
    return (_isExecuting(target, selector), 0);
} else if (selector == IAccessManaged.setAuthority.selector) {
    (bool isAdmin, uint32 executionDelay) = hasRole(ADMIN_ROLE, caller);
    uint32 adminDelay = getTargetAdminDelay(target);
    uint32 setAuthorityDelay = uint32(Math.max(executionDelay, adminDelay));
    return isAdmin ? (setAuthorityDelay == 0, setAuthorityDelay) : (false, 0);
} else {
    uint64 roleId = getTargetFunctionRole(target, selector);
    (bool isMember, uint32 currentDelay) = hasRole(roleId, caller);
    return isMember ? (currentDelay == 0, currentDelay) : (false, 0);
}

