unchecked {
    uint256 left = (index + 1) % cardinality; // oldest observation
    uint256 right = left + cardinality - 1; // newest observation
    uint256 mid;
    while (true) {
        mid = (left + right) / 2;

        beforeOrAt = self[mid % cardinality];

        // we've landed on an uninitialized tick, keep searching higher (more recently)
        if (!beforeOrAt.initialized) {
            left = mid + 1;
            continue;
        }

        atOrAfter = self[(mid + 1) % cardinality];

        bool targetAtOrAfter = lte(time, beforeOrAt.blockTimestamp, target);

        // check if we've found the answer!
        if (targetAtOrAfter && lte(time, target, atOrAfter.blockTimestamp)) break;

        if (!targetAtOrAfter) right = mid - 1;
        else left = mid + 1;
    }
}

for (uint256 index = 0; index < dequeued.length; index = index.add(1)) {
  uint256 proposalId = dequeued[index];
  Proposals.Proposal storage proposal = proposals[proposalId];
  bool isVotingReferendum = (getProposalDequeuedStage(proposal) == Proposals.Stage.Referendum);

  if (!isVotingReferendum) {
    continue;
  }

  VoteRecord storage voteRecord = voter.referendumVotes[index];
  // skip if vote record is not for this proposal
  if (voteRecord.proposalId != proposalId) {
    continue;
  }

  uint256 votesCast = voteRecord.yesVotes.add(voteRecord.noVotes).add(voteRecord.abstainVotes);
  maxReferendumUsed = Math.max(
    maxReferendumUsed,
    // backward compatibility for transition period - this should be updated later on
    votesCast == 0 ? voteRecord.deprecated_weight : votesCast
  );
}

for (uint i; i < levelRate.length; i++) {
  address payable parent = userAccount.referrer;
  Account storage parentAccount = accounts[userAccount.referrer];

  if (parent == address(0)) {
    break;
  }

  if(onlyRewardActiveReferrers && parentAccount.lastActiveTimestamp.add(secondsUntilInactive) >= getTime() || !onlyRewardActiveReferrers) {
    uint c = value.mul(referralBonus).div(decimals);
    c = c.mul(levelRate[i]).div(decimals);
    c = c.mul(getRefereeBonusRate(parentAccount.referredCount)).div(decimals);

    totalReferal = totalReferal.add(c);

    parentAccount.reward = parentAccount.reward.add(c);
    parent.transfer(c);
    emit PaidReferral(msg.sender, parent, c, i + 1);
  }

  userAccount = parentAccount;
}

if (totalSupply() > 0) {
    uint256 eth_reserve = address(this).balance - msg.value;
    uint256 token_reserve = erc20.balanceOf(address(this));
    uint256 actual_token = (msg.value * token_reserve / eth_reserve) + 1;
    require(actual_token <= max_token, "UniV1: Exceed limit");
    require(erc20.transferFrom(msg.sender, address(this), actual_token), "UniV1: Transfer failed");

    uint256 liquid_minted = msg.value * totalSupply() / eth_reserve;
    _mint(msg.sender, liquid_minted);
    return liquid_minted;

} else {
    //mint initial uni tokens. how many?
    //transfer erc 20 token (eth already added to balance)
    uint256 initial_mint = address(this).balance;
    _mint(msg.sender, initial_mint);
    require(erc20.transferFrom(msg.sender, address(this), max_token), "UniV1: Transfer failed");
    return initial_mint;
}

function _afterAddLiquidity(
    address sender,
    PoolKey calldata key,
    ModifyLiquidityParams calldata params,
    BalanceDelta, /* delta */
    BalanceDelta feeDelta,
    bytes calldata
) internal virtual override returns (bytes4, BalanceDelta) {
    PoolId poolId = key.toId();
    bytes32 positionKey = Position.calculatePositionKey(sender, params.tickLower, params.tickUpper, params.salt);

    // If liquidity was added recently within the `blockNumberOffset`, retain the feeDelta in this hook.
    if (_getBlockNumber() - getLastAddedLiquidityBlock(poolId, positionKey) < blockNumberOffset) {
        _updateLastAddedLiquidityBlock(poolId, positionKey);
        _takeFeesToHook(key, positionKey, feeDelta);

        return (this.afterAddLiquidity.selector, feeDelta);
    }

    _updateLastAddedLiquidityBlock(poolId, positionKey);

    return (this.afterAddLiquidity.selector, BalanceDeltaLibrary.ZERO_DELTA);
}

unchecked {
    int24 truncatedTick = tick;

    int24 tickDelta = tick - last.prevTruncatedTick;

    // optimize for negative case
    if (tickDelta > maxAbsTickDelta || tickDelta < -maxAbsTickDelta) {
        truncatedTick = last.prevTruncatedTick + (tickDelta > 0 ? maxAbsTickDelta : -maxAbsTickDelta);
    }

    uint32 timeDelta = blockTimestamp - last.blockTimestamp;
    return Observation({
        blockTimestamp: blockTimestamp,
        prevTruncatedTick: truncatedTick,
        tickCumulative: last.tickCumulative + int56(tick) * int56(uint56(timeDelta)),
        tickCumulativeTruncated: last.tickCumulativeTruncated + int56(truncatedTick) * int56(uint56(timeDelta)),
        initialized: true
    });
}

for (uint256 i = 0; i < results.length; i++) {
    transferFrom(
        orderAddressSet.baseToken,
        results[i].maker,
        results[i].taker,
        results[i].baseTokenFilledAmount
    );

    transferFrom(
        orderAddressSet.quoteToken,
        results[i].taker,
        results[i].maker,
        results[i].quoteTokenFilledAmount.
        sub(results[i].makerFee).
        sub(results[i].makerGasFee).
        add(results[i].makerRebate)
    );

    totalFee = totalFee.
    add(results[i].takerFee).
    add(results[i].makerFee).
    add(results[i].makerGasFee).
    add(results[i].takerGasFee).
    sub(results[i].makerRebate);

    emitMatchEvent(results[i], orderAddressSet);
}

if (ifrandom == 1) {
    if (total_number - claimed_number == 1)
        claimed_tokens = remaining_tokens;
    else{
        // reserve minimum amount => (total_number - claimed_number) * 0.1
        uint reserve_amount = (total_number - claimed_number) * minium_value;
        uint distribute_tokens = remaining_tokens - reserve_amount;
        claimed_tokens = random(seed, nonce) % (distribute_tokens * 2/ (total_number - claimed_number));

        // minimum claimed_tokens for user is 0.1 ; and round the claimed_tokens to decimal 0.1
        claimed_tokens = claimed_tokens < minium_value ? minium_value : (claimed_tokens - (claimed_tokens % minium_value));
    }
} else {
    if (total_number - claimed_number == 1)
        claimed_tokens = remaining_tokens;
    else
        claimed_tokens = remaining_tokens/(total_number - claimed_number);

}

